import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Define a maximum buffer size to prevent buffer overflow
        int maxBufferSize = 10;

        if (input.length() > maxBufferSize) {
            System.out.println("Input string exceeds maximum buffer size. Exiting...");
            return;
        }

        byte[] buffer = new byte[maxBufferSize];
        Arrays.fill(buffer, (byte) 0); // Initialize buffer with zeros

        System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());

        System.out.println("Buffer contents: " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
